import sqlite3; conn = sqlite3.connect('amazon_offers_history.db'); c = conn.cursor(); c.execute("UPDATE cheapest_offers_history SET image_url = 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/88/Nintendo-Switch-wJoyCons-BlRd-Standing-Fr.png/600px-Nintendo-Switch-wJoyCons-BlRd-Standing-Fr.png', url = 'https://www.nintendo.com/pt-br/hardware/switch/' WHERE variant_name LIKE '%Switch%'"); c.execute("UPDATE cheapest_offers_history SET image_url = 'https://m.media-amazon.com/images/I/61H40LspT2L._AC_SX679_.jpg', url = 'https://www.nintendo.com/pt-br/store/controls/' WHERE variant_name LIKE '%Joy-Con%'"); conn.commit(); conn.close(); print('Feito')
